module RefModule(
    input [15:0] in,
    output reg [3:0] ones_count
);integer obf_i;
    always @(*) begin
        ones_count = 0;
        for (obf_i = 0; obf_i < 16; obf_i = obf_i + 1) begin
            if (in[obf_i] == 1'b1) begin
                ones_count = ones_count + 1;
            end
        end
    end
endmodule
